package com.interview.incidentrca.controller;
import com.interview.incidentrca.dto.*;import com.interview.incidentrca.service.AnalyticsService;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequiredArgsConstructor public class AnalyticsController{private final AnalyticsService analytics; @GetMapping("/api/analytics/severity") List<CountResponse> severity(){return analytics.severity();} @GetMapping("/api/analytics/status") List<CountResponse> status(){return analytics.status();} @GetMapping("/api/analytics/top-services") List<CountResponse> top(){return analytics.topServices();} @GetMapping("/api/analytics/sla-breaches") Map<String,Object> sla(){return analytics.slaBreaches();} @GetMapping("/api/audit-logs") @PreAuthorize("hasRole('ADMIN')") Page<AuditLogResponse> audit(Pageable p){return analytics.audit(p);} }
